import React, { useRef, useEffect, useState, useMemo } from "react";
import styled, { ThemeProvider } from "styled-components";

// Import local images
import Image1 from "../assets/products/image1.png";
import Image2 from "../assets/products/image2.png";
import Image3 from "../assets/products/image3.png";
import Image4 from "../assets/products/image4.png";

// Define your theme interface
interface AppTheme {
  itemHeight: number;
  gap: number;
  colors: string[];
}

// Configuration
const CONFIG = {
  scrollSpeed: 0.5,
  gap: 20,
  colors: ["#f5f5f5", "#e0e0e0", "#ebebeb", "#f0f0f0"],
  images: [Image1, Image2, Image3, Image4],
};

// Define props for Card component
interface CardProps {
  index: number;
}

// Styled components with proper typing
const CarouselContainer = styled.div`
  width: 100%;
  height: 100%;
  position: relative;
  perspective: 1000px;
  overflow: hidden;
`;

const RailsContainer = styled.div`
  display: flex;
  justify-content: space-between;
  width: 100%;
  height: 100%;
  padding: 0 5%;
  transform-style: preserve-3d;

  @media (max-width: 768px) {
    padding: 0 2%;
    transform: rotateX(45deg);
  }

  @media (min-width: 769px) {
    transform: rotateX(55deg);
  }
`;

const RailColumn = styled.div<{ columns: number }>`
  width: calc(${(props) => 100 / props.columns}% - 8px);
  height: 100%;
  position: relative;
`;

interface RailProps {
  offset: number;
}

const Rail = styled.div<RailProps>`
  position: absolute;
  width: 100%;
  transform: translate3d(0, ${(props) => props.offset}px, 0);
  will-change: transform;
`;

const Card = styled.div<CardProps>`
  width: 100%;
  height: ${(props) => props.theme.itemHeight}px;
  margin-bottom: ${(props) => props.theme.gap}px;
  background: ${(props) =>
    props.theme.colors[props.index % props.theme.colors.length]};
  border-radius: 12px;
  border: 2.5px solid #84cc16;
  box-shadow: 0 0px 8px 0px rgba(163, 230, 53, 0.9);
  position: relative;
  overflow: hidden;
`;

const ProductImage = styled.img`
  width: 100%;
  height: 100%;
  object-fit: cover;
  transition: transform 0.3s ease;
  filter: saturate(0);

  &:hover {
    transform: scale(1.05);
    filter: saturate(1);
  }
`;

const DataList: React.FC = () => {
  const [offsets, setOffsets] = useState<number[]>([]);
  const [config, setConfig] = useState({
    columns: 4,
    itemsPerColumn: 4,
    itemHeight: 180,
  });
  const requestRef = useRef<number>(null);
  const lastTimeRef = useRef<number>(0);
  const containerRef = useRef<HTMLDivElement>(null);

  // Responsive configuration
  useEffect(() => {
    const handleResize = () => {
      if (window.innerWidth < 640) {
        setConfig({
          columns: 2,
          itemsPerColumn: 4,
          itemHeight: 120,
        });
      } else if (window.innerWidth < 768) {
        setConfig({
          columns: 3,
          itemsPerColumn: 4,
          itemHeight: 140,
        });
      } else {
        setConfig({
          columns: 4,
          itemsPerColumn: 4,
          itemHeight: 180,
        });
      }
    };

    handleResize();
    window.addEventListener("resize", handleResize);
    return () => window.removeEventListener("resize", handleResize);
  }, []);

  // Initialize offsets when config changes
  useEffect(() => {
    setOffsets(Array(config.columns).fill(0));
  }, [config.columns]);

  const singleColumnHeight = useMemo(
    () => (config.itemHeight + CONFIG.gap) * config.itemsPerColumn,
    [config.itemHeight, config.itemsPerColumn]
  );

  const columnItems = useMemo(() => {
    return Array.from({ length: config.columns }).map((_, columnIndex) => {
      const items = [];

      for (let set = 0; set < 2; set++) {
        for (let i = 0; i < config.itemsPerColumn; i++) {
          const imageIndex = (columnIndex + i) % CONFIG.images.length;
          items.push(
            <Card key={`${columnIndex}-${set}-${i}`} index={i}>
              <ProductImage
                src={CONFIG.images[imageIndex]}
                alt={`Product ${imageIndex + 1}`}
                loading="lazy"
              />
            </Card>
          );
        }
      }

      return items;
    });
  }, [config.columns, config.itemsPerColumn]);

  const animate = (time: number) => {
    if (!lastTimeRef.current) lastTimeRef.current = time;
    const deltaTime = time - lastTimeRef.current;
    lastTimeRef.current = time;

    setOffsets((prev) => {
      if (prev.length !== config.columns) return prev;

      const speeds = [0.5, 0.7, 0.9, 0.6].slice(0, config.columns);
      return prev.map((offset, i) => {
        let newOffset =
          offset - speeds[i] * CONFIG.scrollSpeed * (deltaTime / 16);

        if (newOffset <= -singleColumnHeight) {
          newOffset += singleColumnHeight;
        }

        return newOffset;
      });
    });

    requestRef.current = requestAnimationFrame(animate);
  };

  useEffect(() => {
    requestRef.current = requestAnimationFrame(animate);
    return () => {
      if (requestRef.current) cancelAnimationFrame(requestRef.current);
    };
  }, [singleColumnHeight, config.columns]);

  // Create theme object
  const theme: AppTheme = {
    itemHeight: config.itemHeight,
    gap: CONFIG.gap,
    colors: CONFIG.colors,
  };

  return (
    <ThemeProvider theme={theme}>
      <div
        className="relative w-full xl:max-w-[1440px] mx-auto h-[200px] md:h-[250px] lg:h-[400px] mt-20 md:mt-28 lg:mt-32 overflow-hidden"
        ref={containerRef}
      >
        <div className="h-24 md:h-32 lg:h-52 w-full z-10 absolute -top-1 left-0 bg-gradient-to-b from-black to-transparent"></div>
        <div className="h-full w-32 z-10 absolute top-0 left-0 bg-gradient-to-r from-black to-transparent"></div>
        <CarouselContainer>
          <RailsContainer>
            {Array.from({ length: config.columns }).map((_, i) => (
              <RailColumn key={i} columns={config.columns}>
                <Rail offset={offsets[i] || 0}>{columnItems[i]}</Rail>
              </RailColumn>
            ))}
          </RailsContainer>
        </CarouselContainer>
        <div className="h-full w-32 z-10 absolute top-0 right-0 bg-gradient-to-l from-black to-transparent"></div>
        <div className="h-24 md:h-32 lg:h-52 w-full z-10 absolute -bottom-1 left-0 bg-gradient-to-t from-black to-transparent"></div>
      </div>
    </ThemeProvider>
  );
};

export default DataList;
